          <motion.div
            className="stats-grid"
            variants={stagger}
            initial="hidden"
            whileInView="visible"
            viewport={{ once: true, margin: '-60px' }}
          >
            {stats.map(({ value, label }) => (
              <motion.div key={value} className="stat-card" variants={child}>
